namespace sv_ece2ef5e2c134789a8f9c37cdcd81908.Services;

/// <summary>
/// Holds all wizard data for a single applicant session.
/// </summary>
public class WizardState
{
    // Step tracking
    public int CurrentStep { get; set; } = 1;
    public HashSet<int> CompletedSteps { get; set; } = new();

    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobEntry> Experience { get; set; } = new();

    // Step 3: References
    public List<Reference> References { get; set; } = new();

    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Duration { get; set; } = string.Empty;
}

public class Reference
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string ContactInfo { get; set; } = string.Empty;
}

using System.Collections.Concurrent;

namespace sv_ece2ef5e2c134789a8f9c37cdcd81908.Services;

/// <summary>
/// Singleton service that stores wizard state per session.
/// Both the static layout (SSR) and interactive pages (SignalR) resolve
/// the same instance, enabling shared state across render boundaries.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardState> _sessions = new();

    public WizardState GetOrCreate(string sessionId)
    {
        return _sessions.GetOrAdd(sessionId, _ => new WizardState());
    }

    public void Remove(string sessionId)
    {
        _sessions.TryRemove(sessionId, out _);
    }

    /// <summary>
    /// Periodically call this to remove stale sessions (optional cleanup).
    /// </summary>
    public void RemoveExpired(TimeSpan maxAge)
    {
        var cutoff = DateTime.UtcNow - maxAge;
        foreach (var kvp in _sessions)
        {
            if (kvp.Value.CreatedAt < cutoff)
            {
                _sessions.TryRemove(kvp.Key, out _);
            }
        }
    }
}

