namespace sv_ece2ef5e2c134789a8f9c37cdcd81908.Services;

/// <summary>
/// Ensures every request has a WizardSessionId cookie.
/// This gives each browser tab/user a stable identity that both
/// the static layout and interactive components can reference.
/// </summary>
public class WizardSessionMiddleware
{
    private readonly RequestDelegate _next;
    public const string CookieName = "WizardSessionId";

    public WizardSessionMiddleware(RequestDelegate next)
    {
        _next = next;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        if (!context.Request.Cookies.ContainsKey(CookieName))
        {
            var sessionId = Guid.NewGuid().ToString("N");
            context.Response.Cookies.Append(CookieName, sessionId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                MaxAge = TimeSpan.FromHours(4)
            });
            // Make it available to downstream components on this first request
            context.Items[CookieName] = sessionId;
        }

        await _next(context);
    }
}

public static class WizardSessionMiddlewareExtensions
{
    public static string? GetWizardSessionId(this HttpContext context)
    {
        // Prefer cookie; fall back to Items for the first request (before cookie round-trips)
        return context.Request.Cookies[WizardSessionMiddleware.CookieName]
            ?? context.Items[WizardSessionMiddleware.CookieName] as string;
    }
}

