﻿@inherits LayoutComponentBase
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_ece2ef5e2c134789a8f9c37cdcd81908.Services.WizardStateService WizardService
@using sv_ece2ef5e2c134789a8f9c37cdcd81908.Services

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardPage)
            {
                <WizardProgressBar CurrentStep="@WizardState.CurrentStep"
                                   CompletedSteps="@WizardState.CompletedSteps"
                                   TotalSteps="4" />
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private WizardState WizardState { get; set; } = new();
    private bool IsWizardPage => HttpContextAccessor.HttpContext?.Request.Path
        .StartsWithSegments("/apply") == true;

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext?.GetWizardSessionId();
        if (!string.IsNullOrEmpty(sessionId))
        {
            WizardState = WizardService.GetOrCreate(sessionId);
        }
    }
}

