@namespace sv_ece2ef5e2c134789a8f9c37cdcd81908.Components.Layout

<div class="wizard-progress d-flex align-items-center gap-2 me-auto">
    @for (int i = 1; i <= TotalSteps; i++)
    {
        var step = i;
        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;

        <a href="@GetStepUrl(step)"
           class="badge @(isCompleted ? "bg-success" : isCurrent ? "bg-primary" : "bg-secondary")">
            @step
        </a>
    }
    <span class="ms-2 small text-muted">Step @CurrentStep of @TotalSteps</span>
</div>

@code {
    [Parameter] public int CurrentStep { get; set; } = 1;
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public int TotalSteps { get; set; } = 4;

    private static string GetStepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info"
    };
}

