using Microsoft.AspNetCore.Components;

namespace sv_ece2ef5e2c134789a8f9c37cdcd81908.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Handles bridging the session ID
/// from prerender (where HttpContext is available) to interactive mode
/// (where it isn't) using PersistentComponentState.
/// </summary>
public abstract class WizardPageBase : ComponentBase, IDisposable
{
    [Inject] protected Services.WizardStateService WizardService { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;

    protected Services.WizardState WizardState { get; private set; } = new();
    protected abstract int StepNumber { get; }

    private PersistingComponentStateSubscription _subscription;
    private string _sessionId = string.Empty;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        // During prerender (SSR), HttpContext is available
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _sessionId = Services.WizardSessionMiddlewareExtensions
                .GetWizardSessionId(httpContext) ?? string.Empty;
        }

        // During interactive mode, retrieve from persisted state
        if (string.IsNullOrEmpty(_sessionId))
        {
            PersistentState.TryTakeFromJson<string>("WizardSessionId", out var persisted);
            _sessionId = persisted ?? string.Empty;
        }

        if (!string.IsNullOrEmpty(_sessionId))
        {
            WizardState = WizardService.GetOrCreate(_sessionId);
            WizardState.CurrentStep = StepNumber;
        }
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("WizardSessionId", _sessionId);
        return Task.CompletedTask;
    }

    protected void MarkStepCompleted()
    {
        WizardState.CompletedSteps.Add(StepNumber);
    }

    protected void NavigateToStep(int step)
    {
        var url = step switch
        {
            1 => "/apply/personal-info",
            2 => "/apply/experience",
            3 => "/apply/references",
            4 => "/apply/review",
            _ => "/apply/personal-info"
        };
        Navigation.NavigateTo(url);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

