@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Apply - Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<EditForm Model="WizardState" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText @bind-Value="WizardState.Name" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText @bind-Value="WizardState.Email" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText @bind-Value="WizardState.Phone" class="form-control" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override int StepNumber => 1;

    private void Next()
    {
        MarkStepCompleted();
        NavigateToStep(2);
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inherits WizardPageBase
@using sv_ece2ef5e2c134789a8f9c37cdcd81908.Services

<PageTitle>Apply - Experience</PageTitle>

<h3>Step 2: Work Experience</h3>

@foreach (var job in WizardState.Experience)
{
    <div class="card mb-2 p-3">
        <strong>@job.Title</strong> at @job.Company (@job.Duration)
    </div>
}

<div class="border rounded p-3 mb-3">
    <h5>Add Experience</h5>
    <div class="mb-2">
        <label class="form-label">Company</label>
        <input @bind="newJob.Company" class="form-control" />
    </div>
    <div class="mb-2">
        <label class="form-label">Job Title</label>
        <input @bind="newJob.Title" class="form-control" />
    </div>
    <div class="mb-2">
        <label class="form-label">Duration</label>
        <input @bind="newJob.Duration" class="form-control" />
    </div>
    <button class="btn btn-outline-primary btn-sm" @onclick="AddJob">+ Add</button>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="() => NavigateToStep(1)">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override int StepNumber => 2;

    private JobEntry newJob = new();

    private void AddJob()
    {
        if (!string.IsNullOrWhiteSpace(newJob.Company))
        {
            WizardState.Experience.Add(newJob);
            newJob = new();
        }
    }

    private void Next()
    {
        MarkStepCompleted();
        NavigateToStep(3);
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inherits WizardPageBase
@using sv_ece2ef5e2c134789a8f9c37cdcd81908.Services

<PageTitle>Apply - References</PageTitle>

<h3>Step 3: References</h3>

@foreach (var r in WizardState.References)
{
    <div class="card mb-2 p-3">
        <strong>@r.Name</strong> — @r.Relationship (@r.ContactInfo)
    </div>
}

<div class="border rounded p-3 mb-3">
    <h5>Add Reference</h5>
    <div class="mb-2">
        <label class="form-label">Name</label>
        <input @bind="newRef.Name" class="form-control" />
    </div>
    <div class="mb-2">
        <label class="form-label">Relationship</label>
        <input @bind="newRef.Relationship" class="form-control" />
    </div>
    <div class="mb-2">
        <label class="form-label">Contact Info</label>
        <input @bind="newRef.ContactInfo" class="form-control" />
    </div>
    <button class="btn btn-outline-primary btn-sm" @onclick="AddReference">+ Add</button>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="() => NavigateToStep(2)">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override int StepNumber => 3;

    private Reference newRef = new();

    private void AddReference()
    {
        if (!string.IsNullOrWhiteSpace(newRef.Name))
        {
            WizardState.References.Add(newRef);
            newRef = new();
        }
    }

    private void Next()
    {
        MarkStepCompleted();
        NavigateToStep(4);
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@inherits WizardPageBase

<PageTitle>Apply - Review</PageTitle>

<h3>Step 4: Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@WizardState.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@WizardState.Email</dd>
        <dt class="col-sm-3">Phone</dt>
        <dd class="col-sm-9">@WizardState.Phone</dd>
    </dl>
</div>

<div class="card mb-3 p-3">
    <h5>Experience</h5>
    @if (WizardState.Experience.Any())
    {
        <ul class="list-unstyled mb-0">
            @foreach (var job in WizardState.Experience)
            {
                <li>@job.Title at @job.Company (@job.Duration)</li>
            }
        </ul>
    }
    else
    {
        <p class="text-muted mb-0">No experience added.</p>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (WizardState.References.Any())
    {
        <ul class="list-unstyled mb-0">
            @foreach (var r in WizardState.References)
            {
                <li>@r.Name — @r.Relationship (@r.ContactInfo)</li>
            }
        </ul>
    }
    else
    {
        <p class="text-muted mb-0">No references added.</p>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="() => NavigateToStep(3)">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    protected override int StepNumber => 4;
    private bool submitted;

    private void Submit()
    {
        MarkStepCompleted();
        submitted = true;
    }
}

